import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";

const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey =
    "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNuYWt5YW1keWRxeGlzdGRhdmZnIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTM5NDIzNTEsImV4cCI6MjA2OTUxODM1MX0.mAVSru38H63peSy0iH6nDdJ0WBxBwQcoVJwYMy9UKBo";

const supabase = createClient(supabaseUrl, supabaseKey);

const columnOrder = [
    "PROJE ADI",
    "TALEP",
    "TEDARİK",
    "VERİLEMEYEN",
    "TED. %",
    "SPOT",
    "FİLO",
    "TESİSTE",
    "GELECEK",
    "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER",
    "HEDEF ALTI SEFER",
    "HEDEF SEFER",
    "HEDEFSİZ SEFER",
];

function App() {
    const [data, setData] = useState([]);

    useEffect(() => {
        async function fetchData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.json_data) {
                setData(data.json_data);
            }
        }

        fetchData();
    }, []);

    return (
        <div className="min-h-screen bg-gray-100 p-6">
            <h1 className="text-3xl font-bold text-center text-blue-700 mb-8">
                TEDARİK PERFORMANS RAPORU
            </h1>

            {data.length > 0 ? (
                <div className="overflow-x-auto bg-white rounded-xl shadow-lg">
                    <table className="min-w-full text-sm text-left text-gray-700">
                        <thead className="bg-blue-600 text-white text-xs uppercase tracking-wider">
                            <tr>
                                {columnOrder.map((col) => (
                                    <th key={col} className="px-6 py-3">
                                        {col}
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                            {data.slice(1).map((row, idx) => (
                                <tr
                                    key={idx}
                                    className="hover:bg-blue-50 transition duration-200"
                                >
                                    {columnOrder.map((col, i) => (
                                        <td key={i} className="px-6 py-4 whitespace-nowrap">
                                            {row[col]}
                                        </td>
                                    ))}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            ) : (
                <p className="text-center text-gray-500 mt-8">Yükleniyor...</p>
            )}
        </div>
    );
}

export default App;
